import{_ as d,o as e,c as o,a as s,b as t}from"./index-qegPpB8D.js";const i={class:"legal-section"},n={__name:"PoliticaPrivacidad",setup(l){return e(()=>{document.title="Política de Privacidad | Reglado Maps"}),(r,a)=>(t(),o("section",i,[...a[0]||(a[0]=[s('<div class="legal-card" data-v-ad47fb0d><h1 class="h1" data-v-ad47fb0d>Política de Privacidad</h1><div class="legal-content" data-v-ad47fb0d><p data-v-ad47fb0d><strong data-v-ad47fb0d>1. ¿QUIÉN ES EL RESPONSABLE DEL TRATAMIENTO DE SUS DATOS?</strong></p><p data-v-ad47fb0d>El responsable del tratamiento de los datos personales es REGLADO GROUP S.L, con CIF B23982762 y domicilio en AVDA. ISLA GRACIOSA, 7 PISO 1º DESPACHOS 5-6 28703 SAN SEBASTIÁN DE LOS REYES (Madrid).</p><p data-v-ad47fb0d>Contacto: info@regladoconsultores.com</p><p data-v-ad47fb0d><strong data-v-ad47fb0d>2. ¿CON QUÉ FINALIDAD TRATAMOS SUS DATOS PERSONALES?</strong></p><p data-v-ad47fb0d>En REGLADO GROUP S.L tratamos la información que nos facilitan las personas interesadas con las siguientes finalidades en el marco de Reglado Maps:</p><ul data-v-ad47fb0d><li data-v-ad47fb0d>Gestionar el acceso a la plataforma cartográfica y sus funcionalidades.</li><li data-v-ad47fb0d>Tramitar solicitudes de información técnica sobre activos energéticos.</li><li data-v-ad47fb0d>Mejorar la experiencia de usuario mediante el análisis de la interacción con el mapa.</li><li data-v-ad47fb0d>Remitir comunicaciones sobre actualizaciones de la plataforma cuando sea autorizado.</li></ul><p data-v-ad47fb0d><strong data-v-ad47fb0d>3. ¿POR CUÁNTO TIEMPO CONSERVAREMOS SUS DATOS?</strong></p><p data-v-ad47fb0d>Los datos personales proporcionados se conservarán mientras se mantenga la relación contractual/comercial o durante los años necesarios para cumplir con las obligaciones legales.</p><p data-v-ad47fb0d><strong data-v-ad47fb0d>4. ¿CUÁL ES LA LEGITIMACIÓN PARA EL TRATAMIENTO DE SUS DATOS?</strong></p><p data-v-ad47fb0d>La base legal para el tratamiento de sus datos es el consentimiento del interesado al acceder a la plataforma o al realizar consultas específicas.</p><p data-v-ad47fb0d><strong data-v-ad47fb0d>5. ¿A QUÉ DESTINATARIOS SE COMUNICARÁN SUS DATOS?</strong></p><p data-v-ad47fb0d>Los datos no se cederán a terceros salvo en los casos en que exista una obligación legal o sea necesario para la prestación del servicio geoespacial solicitado.</p><p data-v-ad47fb0d><strong data-v-ad47fb0d>6. ¿CUÁLES SON SUS DERECHOS AL FACILITARNOS SUS DATOS?</strong></p><p data-v-ad47fb0d>Cualquier persona tiene derecho a obtener confirmación sobre si en REGLADO GROUP S.L estamos tratando datos personales que les conciernan, o no. Las personas interesadas tienen derecho a:</p><ul data-v-ad47fb0d><li data-v-ad47fb0d>Acceder a sus datos personales.</li><li data-v-ad47fb0d>Solicitar la rectificación de los datos inexactos.</li><li data-v-ad47fb0d>Solicitar su supresión cuando los datos ya no sean necesarios.</li><li data-v-ad47fb0d>Solicitar la limitación de su tratamiento.</li><li data-v-ad47fb0d>Oponerse al tratamiento de sus datos.</li><li data-v-ad47fb0d>Derecho a la portabilidad de los datos.</li></ul><p data-v-ad47fb0d>Para ejercer estos derechos, puede dirigirse a info@regladoconsultores.com adjuntando copia de su DNI.</p></div></div>',1)])]))}},p=d(n,[["__scopeId","data-v-ad47fb0d"]]);export{p as default};
